import pandas as pd
import numpy as np

def task_func(fruit_data):
    if not fruit_data:
        return pd.DataFrame()

    # Group fruit_data by fruit name and calculate total count and average count for each group
    grouped = pd.DataFrame(fruit_data, columns=['Fruit', 'Count']).groupby('Fruit').agg({'Count': [np.sum, np.mean]}).rename(columns={'Count': ['Total Count', 'Average Count']})

    # Set the index of the DataFrame to the fruit names
    grouped.index.name = None
    return grouped.sort_index()
